import Testmonial from "../components/Testimonial";
import { useEffect } from "react";

function OurWrok() {
    useEffect(() => {
        const observer = new IntersectionObserver((entries) => {
            entries.forEach((entry) => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('aos-animate');
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.05, rootMargin: '0px 0px -50px 0px' });

        const elements = document.querySelectorAll('[data-aos]');
        elements.forEach((el) => observer.observe(el));

        return () => {
            elements.forEach((el) => observer.unobserve(el));
        };
    }, []);

    return (
        <>
            <section >
                <div className='container pt-5'>
                    <div className='row'>
                        <div className='col-md-6 text-end pe-5  d-flex justify-content-end align-items-center' data-aos="fade-right" data-aos-duration="800">
                            <h1>Our Work</h1>
                        </div>
                        <div className='col-md-6 my-5' data-aos="fade-left" data-aos-duration="800">
                            <p>Explore a selection of projects, campaigns, and creative collaborations we have been part of. Each project reflects our commitment to connecting talented models with brands, photographers, and creative teams to produce impactful visual work.</p>
                        </div>
                    </div>
                </div>
            </section >
            <section >
                <div className="container py-5">
                    <div className="gallery">

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="0">
                            <img src={process.env.PUBLIC_URL + '/images/women-using-laptops-sofa-together.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="50">
                            <img src={process.env.PUBLIC_URL + '/images/fashion-designer-is-working-project.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="100">
                            <img src={process.env.PUBLIC_URL + '/images/silhouette-woman-with-laptop-side-view-shadow-back-lit-young.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="150">
                            <img src={process.env.PUBLIC_URL + '/images/black-white-portrait-beautiful-woman-posing-indoors-chair.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="0">
                            <img src={process.env.PUBLIC_URL + '/images/guy-stand-city-street-look-camera-around.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="50">
                            <img src={process.env.PUBLIC_URL + '/images/portrait-young-beautiful-brunette-woman-girl-model-with-nude-makeup-summer-hipster-clothes-posing-near-wall.jpg'} alt="" />
                        </div>
                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="100">
                            <img src={process.env.PUBLIC_URL + '/images/medium-shot-woman-holding-tablet.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="150">
                            <img src={process.env.PUBLIC_URL + '/images/silhouette-woman-with-laptop-side-view-shadow-back-lit-young.jpg'} alt="" />
                        </div>

                        <div className="gallery-item" data-aos="zoom-in" data-aos-duration="600" data-aos-delay="50">
                            <img src={process.env.PUBLIC_URL + '/images/women-using-laptops-sofa-together.jpg'} alt="" />
                        </div>
                    </div>
                </div>
            </section >
            <section className='cls-odd'>
                <Testmonial />
            </section>
        </>
    )
}

export default OurWrok;